85	  // Item-specific modifiers
86	  it("should add 50% curse surcharge to the cursed item's base premium", () => {
87	    expect(quote([{ type: "sword", cursed: true }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(155);
88	  });
89	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
90	  it.todo("should not add high-enchantment surcharge for enchantment 4");
91	  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");
92	
93	  // Modifier scope on multi-item policies
94	  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");
