103	
104	  // Integration examples
105	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
106	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
107	
108	  // Error case
