113	  // Standard reimbursement minus deductible
114	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
115	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
116	
117	  // High-enchantment clause
118	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
119	
120	  // Dragon-material clause
